from pathlib import Path
from decimal import Decimal, ROUND_HALF_UP
import csv, re, shutil
import fitz, pytesseract
from PIL import Image

DOCS = Path('/app/documents')
INVOICES = Path('/app/invoices')
OTHER = Path('/app/other')
INVOICES.mkdir(exist_ok=True)
OTHER.mkdir(exist_ok=True)

invoice_terms = [
    'invoice', 'bill to', 'amount due', 'total due', 'tax invoice',
    'invoice number', 'invoice #', 'invoice no', 'balance due',
    'grand total', 'remit to'
]

label_patterns = {
    'total': [r'\bgrand\s*total\b', r'\btotal\b', r'\btotalprice\b'],
    'amount_due': [r'\bamount\s*due\b'],
    'vat': [r'\bvat\b', r'\bgst\b', r'\btax\b'],
}

money_pat = re.compile(r'(?<!\d)(?:\$\s*)?\d{1,3}(?:[\s,]\d{3})*(?:[.,]\d+)?|(?<!\d)(?:\$\s*)?\d+(?:[.,]\d+)?')


def normalize_number(token: str):
    s = token.strip()
    s = s.replace('$', '').replace('€', '').replace('£', '').replace('USD', '').replace('EUR', '').replace('GBP', '')
    s = re.sub(r'[^0-9,\.\-\s]', '', s).strip()
    if not s:
        return None
    s = re.sub(r'\s+', ' ', s)
    if ',' in s and '.' in s:
        if s.rfind(',') > s.rfind('.'):
            s = s.replace('.', '').replace(' ', '').replace(',', '.')
        else:
            s = s.replace(',', '').replace(' ', '')
    elif ',' in s:
        if re.search(r',\d{1,2}$', s):
            s = s.replace(' ', '').replace(',', '.')
        else:
            s = s.replace(',', '').replace(' ', '')
    else:
        if re.search(r'\.\d{1,2}$', s):
            s = s.replace(' ', '')
        else:
            s = s.replace(' ', '')
    try:
        return Decimal(s)
    except Exception:
        return None


def extract_text(path: Path) -> str:
    if path.suffix.lower() == '.pdf':
        doc = fitz.open(path)
        return '\n'.join(page.get_text() for page in doc)
    img = Image.open(path)
    return pytesseract.image_to_string(img, config='--psm 6')


def is_invoice(text: str) -> bool:
    low = ' '.join(text.lower().split())
    score = sum(term in low for term in invoice_terms)
    if score >= 1:
        return True
    if 'order id' in low and 'customer details' in low and 'shipper' not in low:
        return True
    return False


def numbers_in_line(line: str):
    vals = []
    for m in money_pat.finditer(line):
        val = normalize_number(m.group(0))
        if val is not None:
            vals.append(val)
    return vals


def line_has_any(line: str, patterns):
    return any(re.search(p, line, re.I) for p in patterns)


def extract_amounts(text: str):
    lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
    total_candidates = []
    amount_due_candidates = []
    vat_candidates = []

    for i, line in enumerate(lines):
        next_line = lines[i+1] if i + 1 < len(lines) else ''
        combo = f"{line} {next_line}".strip()

        if line_has_any(line, label_patterns['total']):
            nums = numbers_in_line(line)
            if nums:
                total_candidates.append(nums[-1])
                if len(nums) >= 2:
                    vat_candidates.append(nums[-2])
            else:
                next_nums = numbers_in_line(next_line)
                if next_nums:
                    total_candidates.append(next_nums[-1])
                    if len(next_nums) >= 2:
                        vat_candidates.append(next_nums[-2])

        if line_has_any(line, label_patterns['amount_due']):
            nums = numbers_in_line(line)
            if nums:
                amount_due_candidates.append(nums[-1])
            else:
                next_nums = numbers_in_line(next_line)
                if next_nums:
                    amount_due_candidates.append(next_nums[-1])

        if line_has_any(line, label_patterns['vat']):
            nums = numbers_in_line(line)
            if nums:
                if re.search(r'\b(vat|gst|tax)\b', line, re.I) and len(nums) == 1:
                    vat_candidates.append(nums[0])
                elif re.search(r'VAT \[%\] Net worth VAT Gross worth', line, re.I):
                    pass
            else:
                next_nums = numbers_in_line(next_line)
                if next_nums:
                    # invoice tables usually list VAT amount as middle value when next line contains net/vat/gross
                    if len(next_nums) >= 2:
                        vat_candidates.append(next_nums[-2])
                    else:
                        vat_candidates.append(next_nums[0])

        if line_has_any(combo, label_patterns['vat']) and line_has_any(combo, label_patterns['total']):
            nums = numbers_in_line(combo)
            if len(nums) >= 2:
                vat_candidates.append(nums[-2])
                total_candidates.append(nums[-1])

    total = total_candidates[-1] if total_candidates else None
    amount_due = amount_due_candidates[-1] if amount_due_candidates else None
    if total is None:
        total = amount_due
    elif amount_due is not None and total != amount_due:
        total = total

    vat = vat_candidates[-1] if vat_candidates else Decimal('0')
    if vat is None:
        vat = Decimal('0')
    if total is None:
        total = Decimal('0')

    return total, vat


def fmt(d: Decimal) -> str:
    q = d.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
    return format(q, 'f')

invoice_rows = []
for path in sorted(DOCS.iterdir()):
    if not path.is_file():
        continue
    text = extract_text(path)
    target_dir = INVOICES if is_invoice(text) else OTHER
    target = target_dir / path.name
    shutil.move(str(path), str(target))
    if target_dir == INVOICES:
        total, vat = extract_amounts(text)
        invoice_rows.append((path.name, total, vat))

invoice_rows.sort(key=lambda x: x[0])
sum_total = sum((row[1] for row in invoice_rows), Decimal('0'))
sum_vat = sum((row[2] for row in invoice_rows), Decimal('0'))

with open(INVOICES / 'summary.csv', 'w', newline='') as f:
    writer = csv.writer(f)
    writer.writerow(['filename', 'total_amount', 'vat_amount'])
    for name, total, vat in invoice_rows:
        writer.writerow([name, fmt(total), fmt(vat)])
    writer.writerow(['total', fmt(sum_total), fmt(sum_vat)])

print('processed', len(invoice_rows), 'invoices')
for row in invoice_rows:
    print(row[0], fmt(row[1]), fmt(row[2]))
print('totals', fmt(sum_total), fmt(sum_vat))
