from pathlib import Path
from decimal import Decimal, ROUND_HALF_UP
import csv, re
import fitz, pytesseract
from PIL import Image

INVOICES = Path('/app/invoices')

invoice_files = sorted([p for p in INVOICES.iterdir() if p.is_file() and p.name != 'summary.csv'])

money_pat = re.compile(r'(?:[$€£]\s*)?(?:\d{1,3}(?: \d{3})+(?:,\d+)?|\d{1,3}(?:,\d{3})+(?:\.\d+)?|\d+\.\d+|\d+,\d+|\d+)')

def extract_text(path: Path) -> str:
    if path.suffix.lower() == '.pdf':
        return '\n'.join(page.get_text() for page in fitz.open(path))
    return pytesseract.image_to_string(Image.open(path), config='--psm 6')

def normalize_number(token: str):
    s = token.strip()
    s = re.sub(r'^[^\d-]+', '', s)
    s = re.sub(r'[^\d.,\- ]+$', '', s)
    s = s.replace(' ', ' ')
    if ',' in s and '.' in s:
        if s.rfind(',') > s.rfind('.'):
            s = s.replace('.', '').replace(' ', '').replace(',', '.')
        else:
            s = s.replace(',', '').replace(' ', '')
    elif ',' in s:
        if re.search(r',\d{1,2}$', s):
            s = s.replace(' ', '').replace(',', '.')
        else:
            s = s.replace(',', '').replace(' ', '')
    else:
        s = s.replace(' ', '')
    try:
        return Decimal(s)
    except Exception:
        return None

def nums(line: str):
    out=[]
    for m in money_pat.finditer(line):
        val = normalize_number(m.group(0))
        if val is not None:
            out.append(val)
    return out

def extract_amounts(text: str):
    lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
    total = None
    amount_due = None
    vat = None
    for i, line in enumerate(lines):
        next_line = lines[i+1] if i+1 < len(lines) else ''
        low = line.lower()
        low_next = next_line.lower()

        if re.search(r'\b(sub\s*total|subtotal)\b', low):
            pass
        elif re.search(r'\b(grand\s*total|totalprice|total)\b', low):
            values = nums(line)
            if values:
                total = values[-1]
                if len(values) >= 3:
                    vat = values[-2]
            else:
                next_values = nums(next_line)
                if next_values:
                    total = next_values[-1]

        if re.search(r'\bamount\s*due\b', low):
            values = nums(line) or nums(next_line)
            if values:
                amount_due = values[-1]

        if 'tax id' in low:
            continue
        if re.search(r'vat\s*\[%\].*vat.*gross', low):
            next_values = nums(next_line)
            if len(next_values) >= 3:
                vat = next_values[-2]
            elif len(next_values) >= 2:
                vat = next_values[-1]
        elif re.search(r'\b(vat|gst|tax)\b', low):
            values = nums(line)
            if len(values) == 1:
                vat = values[0]
            elif len(values) >= 3 and re.search(r'\btotal\b', low):
                vat = values[-2]
            elif not values:
                next_values = nums(next_line)
                if len(next_values) == 1:
                    vat = next_values[0]
                elif len(next_values) >= 3:
                    vat = next_values[-2]

    if total is None:
        total = amount_due or Decimal('0')
    if vat is None:
        vat = Decimal('0')
    return total, vat

def fmt(d: Decimal) -> str:
    return format(d.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP), 'f')

rows=[]
for p in invoice_files:
    total, vat = extract_amounts(extract_text(p))
    rows.append((p.name, total, vat))
rows.sort()

total_sum = sum((r[1] for r in rows), Decimal('0'))
vat_sum = sum((r[2] for r in rows), Decimal('0'))
with open(INVOICES / 'summary.csv', 'w', newline='') as f:
    w = csv.writer(f)
    w.writerow(['filename','total_amount','vat_amount'])
    for name, total, vat in rows:
        w.writerow([name, fmt(total), fmt(vat)])
    w.writerow(['total', fmt(total_sum), fmt(vat_sum)])

for name, total, vat in rows:
    print(name, fmt(total), fmt(vat))
print('TOTAL', fmt(total_sum), fmt(vat_sum))
